sub extract_metadata {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);

    # Extract document information
    my $info = $pdf->info;
    my $author = $info->author;
    my $title = $info->title;
    my $creation_date = $info->creation;

    return ($author, $title, $creation_date);
}

